@media print{
    @page {
        size : 100mm 45mm;
        margin : 0;
    }
}
*{
    border:none;
    box-sizing :0px;
}
    .print-format{
        padding : 1px !important;
    }

body{
margin : 0;
padding : 0;
    
}

.label.empty-label {
    border: 1px dashed #999;
    background-color: #f5f5f5;
}

.label .empty-placeholder {
    text-align: center;
    font-size: 14px;
    color: #999;
    margin-top: 20mm;
}


  .wrapper {
    display: flex;
    justify-content: space-between;
    width: 100%;
    margin-bottom: 0px !important;
    page-break-inside: avoid;
  }
  .label {
    width: 100mm;
    border: 0px ;
 
    box-sizing: border-box;
    background: #fff;
    font-size:12px !important;
    /*min-height: 190px; */
    /*position: relative !important;*/
    /*left :2mm;*/
    /*top:2mm;*/
    /*top:-1px !important;*/
    /*margin : 0px auto;*/
    height :50mm !important;
  }
  .brand-header {
    text-align: center;
    font-weight: 700;
    font-size: 18px;
   
    text-transform: uppercase;
    margin-top:0px auto !important;
  }
  
  span{
      margin:0 !important;
      padding:0 !important;
      line-height: inherit !important;
  }
  
  .details-block {
    font-size: 13px;
    line-height: 1.25 !important;
    font-weight: 500;
     font-family: system-ui;
    text-align: left;
    margin-bottom: 0px;
  }
  .barcode-container {
    text-align: center;
    width: 90%;
    margin-top: 2px; /* Space adjusted because MRP is removed */
  }
  .barcode-container img {
    width: 86%;
    height: 76px; 
    display: block;
    margin: 0 auto;
  }
  .serial-number {
    font-size: 18px; 
    font-weight: 500;
    margin-top: 2px;
    text-align: center;
    letter-spacing: 1px;
  }
  
  .boldtext{
      /*font-weight:bold;*/
      padding-left:4px;
  }
